import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getFeatured, getCategories } from '../services/api';
import ProductCard from '../components/ProductCard';

const Home = () => {
  const [featured, setFeatured] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const [f, c] = await Promise.all([getFeatured(), getCategories()]);
        setFeatured(f.data || []);
        setCategories(c.data || []);
      } catch (e) { console.error(e); }
      finally { setLoading(false); }
    };
    load();
  }, []);

  return (
    <div className="home">
      {/* Hero */}
      <section className="hero" style={{
        background: 'linear-gradient(rgba(26, 26, 46, 0.85), rgba(15, 52, 96, 0.9)), url("https://images.unsplash.com/photo-1441984904996-e0b6ba687e04?w=1600&q=80")',
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundRepeat: 'no-repeat',
        padding: '80px 40px',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        minHeight: '80vh',
        position: 'relative',
        overflow: 'hidden'
      }}>
        <div className="hero-content" style={{
          color: '#ffffff',
          maxWidth: '600px',
          zIndex: 1
        }}>
          <p className="hero-sub" style={{
            color: '#e94560',
            fontSize: '14px',
            textTransform: 'uppercase',
            letterSpacing: '3px',
            marginBottom: '15px',
            fontWeight: '600'
          }}>New Collection 2026</p>
          <h1 style={{
            fontSize: '3.5rem',
            fontWeight: '800',
            marginBottom: '20px',
            lineHeight: '1.2',
            color: '#ffffff'
          }}>Select Your New <br />Perfect Style</h1>
          <p className="hero-desc" style={{
            color: '#e0e0e0',
            fontSize: '1.1rem',
            lineHeight: '1.6',
            marginBottom: '30px'
          }}>Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat is aute irure.</p>
          <div className="hero-btns" style={{
            display: 'flex',
            gap: '15px',
            flexWrap: 'wrap'
          }}>
            <Link to="/products" className="btn-primary btn-lg" style={{
              background: 'linear-gradient(135deg, #e94560, #ff6b6b)',
              color: 'white',
              padding: '12px 30px',
              borderRadius: '25px',
              textDecoration: 'none',
              fontWeight: '600',
              transition: 'all 0.3s ease',
              display: 'inline-block'
            }}>SHOP NOW</Link>
            <Link to="/products?isFeatured=true" className="btn-ghost btn-lg" style={{
              background: 'transparent',
              color: '#ffffff',
              padding: '12px 30px',
              borderRadius: '25px',
              textDecoration: 'none',
              fontWeight: '600',
              border: '2px solid rgba(255,255,255,0.3)',
              transition: 'all 0.3s ease',
              display: 'inline-block'
            }}>View Collection</Link>
          </div>
        </div>
        <div className="hero-image" style={{
          flex: '1',
          minHeight: '400px',
          background: 'url("https://images.unsplash.com/photo-1490481651871-ab68de25d43d?w=800") center/cover',
          borderRadius: '20px',
          position: 'relative',
          display: 'none'
        }}
        onLoad={(e) => { e.target.style.display = 'block'; }}
        >
          <div className="hero-badge" style={{
            position: 'absolute',
            top: '20px',
            right: '20px',
            background: 'linear-gradient(135deg, #372d2f, #292323)',
            color: '#ffffff',
            padding: '10px 20px',
            borderRadius: '25px',
            fontWeight: '700',
            fontSize: '0.875rem',
            letterSpacing: '1px',
            boxShadow: '0 10px 25px rgba(233, 69, 96, 0.3)'
          }}>New Arrivals</div>
        </div>
      </section>

      {/* Categories */}
      <section className="section" style={{
        padding: '80px 40px',
        maxWidth: '1400px',
        margin: '0 auto',
        backgroundColor: '#ffffff'
      }}>
        <div className="section-header" style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: '40px'
        }}>
          <h2 style={{
            fontSize: '2.5rem',
            fontWeight: '800',
            color: '#1a1a2e',
            margin: '0'
          }}>Shop by Category</h2>
          <Link to="/products" style={{
            color: '#e94560',
            textDecoration: 'none',
            fontWeight: '600',
            fontSize: '1.1rem'
          }}>View All →</Link>
        </div>
        <div className="category-grid" style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))',
          gap: '20px',
          marginBottom: '40px'
        }}>
          {['Men', 'Women', 'Kids', 'Accessories', 'Footwear', 'Sale'].map(cat => (
            <Link to={`/products?category=${cat}`} key={cat} className="category-card" style={{
              position: 'relative',
              borderRadius: '12px',
              overflow: 'hidden',
              background: '#f8f9fa',
              textDecoration: 'none',
              transition: 'all 0.3s ease',
              aspectRatio: '1',
              boxShadow: '0 2px 10px rgba(0,0,0,0.05)',
              cursor: 'pointer'
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = 'translateY(-5px)';
              e.currentTarget.style.boxShadow = '0 10px 30px rgba(0,0,0,0.15)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = 'translateY(0)';
              e.currentTarget.style.boxShadow = '0 2px 10px rgba(0,0,0,0.05)';
            }}
            >
              <div className="category-icon" style={{
                width: '100%',
                height: '100%'
              }}>
                <img 
                  src={
                    cat === 'Men' ? 'https://images.unsplash.com/photo-1490578474895-699cd4e2cf59?w=400' : 
                    cat === 'Women' ? 'https://images.unsplash.com/photo-1483985988355-763728e1935b?w=400' : 
                    cat === 'Kids' ? 'https://images.unsplash.com/photo-1519238263530-99bdd11df2ea?w=400' : 
                    cat === 'Accessories' ? 'https://images.unsplash.com/photo-1606760227091-3dd870d97f1d?w=400' : 
                    cat === 'Footwear' ? 'https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=400' : 
                    'https://images.unsplash.com/photo-1470309864661-68328b2cd0a5?w=400'
                  } 
                  alt={cat}
                  loading="lazy"
                  style={{ 
                    width: '100%', 
                    height: '100%', 
                    objectFit: 'cover',
                    transition: 'transform 0.3s ease'
                  }}
                  onError={(e) => {
                    e.target.onerror = null;
                    e.target.src = `https://via.placeholder.com/400x400/1a1a2e/ffffff?text=${cat}`;
                  }}
                />
              </div>
              <span style={{
                position: 'absolute',
                bottom: '0',
                left: '0',
                right: '0',
                padding: '15px',
                background: 'linear-gradient(to top, rgba(0,0,0,0.8), transparent)',
                color: '#ffffff',
                fontWeight: '700',
                fontSize: '1.1rem',
                textAlign: 'center'
              }}>{cat}</span>
            </Link>
          ))}
        </div>
      </section>

      {/* Featured */}
      <section className="section" style={{
        padding: '80px 40px',
        maxWidth: '1400px',
        margin: '0 auto',
        backgroundColor: '#f8f9fa'
      }}>
        <div className="section-header" style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: '40px'
        }}>
          <h2 style={{
            fontSize: '2.5rem',
            fontWeight: '800',
            color: '#1a1a2e',
            margin: '0'
          }}>Featured Products</h2>
          <Link to="/products" style={{
            color: '#e94560',
            textDecoration: 'none',
            fontWeight: '600',
            fontSize: '1.1rem'
          }}>See All →</Link>
        </div>
        {loading ? (
          <div style={{
            textAlign: 'center',
            padding: '60px 20px',
            color: '#666'
          }}>
            <div style={{
              width: '50px',
              height: '50px',
              border: '4px solid #f0f0f0',
              borderTopColor: '#e94560',
              borderRadius: '50%',
              animation: 'spin 1s linear infinite',
              margin: '0 auto 20px'
            }}></div>
            Loading...
          </div>
        ) : (
          <div className="products-grid" style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
            gap: '30px'
          }}>
            {featured.length > 0 ? (
              featured.map(p => <ProductCard key={p._id} product={p} />)
            ) : (
              <div style={{
                gridColumn: '1 / -1',
                textAlign: 'center',
                padding: '60px',
                backgroundColor: '#ffffff',
                borderRadius: '12px',
                color: '#666'
              }}>
                No featured products available at the moment.
              </div>
            )}
          </div>
        )}
      </section>

      {/* Promo Banner */}
      <section className="promo-banner" style={{
        background: 'linear-gradient(135deg, #1a1a2e, #16213e)',
        color: '#ffffff',
        textAlign: 'center',
        padding: '80px 40px',
        marginTop: '40px'
      }}>
        <div className="promo-content">
          <h2 style={{
            fontSize: '2.5rem',
            fontWeight: '800',
            marginBottom: '15px',
            color: '#ffffff'
          }}>Get 20% Off Your First Order</h2>
          <p style={{
            fontSize: '1.2rem',
            color: '#a8b2c1',
            marginBottom: '30px'
          }}>Use code <strong style={{
            backgroundColor: '#e94560',
            padding: '4px 12px',
            borderRadius: '6px',
            color: '#ffffff',
            fontWeight: '700'
          }}>WELCOME20</strong> at checkout</p>
          <Link to="/register" className="btn-primary" style={{
            background: 'linear-gradient(135deg, #e94560, #ff6b6b)',
            color: 'white',
            padding: '12px 30px',
            borderRadius: '25px',
            textDecoration: 'none',
            fontWeight: '600',
            display: 'inline-block',
            transition: 'all 0.3s ease'
          }}
          onMouseEnter={(e) => {
            e.target.style.transform = 'translateY(-2px)';
            e.target.style.boxShadow = '0 10px 25px rgba(233, 69, 96, 0.4)';
          }}
          onMouseLeave={(e) => {
            e.target.style.transform = 'translateY(0)';
            e.target.style.boxShadow = 'none';
          }}
          >Sign Up & Save</Link>
        </div>
      </section>

      <style>{`
        @keyframes spin {
          to { transform: rotate(360deg); }
        }

        @media (max-width: 768px) {
          .section {
            padding: 60px 20px !important;
          }

          h1 {
            font-size: 2.5rem !important;
          }

          h2 {
            font-size: 2rem !important;
          }

          .category-grid {
            grid-template-columns: repeat(auto-fit, minmax(150px, 1fr)) !important;
            gap: 15px !important;
          }

          .products-grid {
            grid-template-columns: repeat(auto-fill, minmax(250px, 1fr)) !important;
            gap: 20px !important;
          }
        }

        @media (max-width: 480px) {
          .hero-btns {
            flex-direction: column !important;
          }

          .category-grid {
            grid-template-columns: repeat(2, 1fr) !important;
          }

          .section {
            padding: 40px 15px !important;
          }
        }
      `}</style>
    </div>
  );
};

export default Home;
